def _shared_find_local_peaks(xs, threshold):
    """Return a list of indices of local peaks in xs that meet the threshold."""
    return [i for i in range(1, len(xs) - 1) if xs[i] > xs[i - 1] and xs[i] >= xs[i + 1] and xs[i] >= threshold]

def _shared_normalize_title(text):
    """Normalize text by lowercasing, replacing non-alphanumerics with spaces, and collapsing whitespace."""
    return " ".join("".join(ch if ch.isalnum() else " " for ch in text.lower()).split())

