def first_peak_after(xs, threshold, start_idx):
    for peak_idx in _shared_find_local_peaks(xs, threshold):
        if peak_idx > start_idx:
            return peak_idx
    return -1

def pair_nearby_peaks(xs, ys, threshold, max_gap):
    x_peaks = _shared_find_local_peaks(xs, threshold)
    y_peaks = _shared_find_local_peaks(ys, threshold)
    pairs = []
    for xp in x_peaks:
        for yp in y_peaks:
            if abs(xp - yp) <= max_gap:
                pairs.append((xp, yp))
                break
    return pairs

def global_argmax_index(xs):
    if not xs:
        return -1
    best_i = 0
    best_v = xs[0]
    for i, value in enumerate(xs[1:], start=1):
        if value > best_v:
            best_i = i
            best_v = value
    return best_i

def dedupe_reference_titles(titles):
    seen = set()
    out = []
    for title in titles:
        key = _shared_normalize_title(title)
        if key not in seen:
            seen.add(key)
            out.append(key)
    return out

def extract_year_tokens(text):
    current = ""
    out = []
    for ch in text:
        if ch.isdigit():
            current += ch
        else:
            if len(current) == 4:
                out.append(int(current))
            current = ""
    if len(current) == 4:
        out.append(int(current))
    return out
